class Solution:
    def minChanges(self, n: int, k: int) -> int:
        if (n & k) != k:
            return -1
        changes = 0
        while n or k:
            n_bit = n & 1
            k_bit = k & 1
            if n_bit > k_bit:
                changes += 1
            n >>= 1
            k >>= 1
        return changes

